import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Testimony {
  id: string;
  author: string;
  title: string;
  content: string;
  date: string;
}

export interface GuestbookEntry {
  id: string;
  author: string;
  message: string;
  date: string;
}

export interface Inquiry {
  id: string;
  name: string;
  email: string;
  subject: string;
  message: string;
  status: 'pending' | 'completed';
  date: string;
}

export interface Sponsorship {
  id: string;
  name: string;
  type: '정기후원' | '일시후원';
  amount: number;
  message?: string;
  date: string;
}

export enum Page {
  Home = 'home',
  About = 'about',
  Ministries = 'ministries',
  Community = 'community',
  Support = 'support',
  Admin = 'admin'
}

import React, { useState, useEffect } from 'react';
import { Page } from './types';
import Navbar from './components/Navbar';
import Footer from './components/Footer';
import Home from './pages/Home';
import About from './pages/About';
import Ministries from './pages/Ministries';
import Community from './pages/Community';
import Support from './pages/Support';
import Admin from './pages/Admin';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<Page>(Page.Home);

  // Simple scroll to top on page change
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [currentPage]);

  const renderPage = () => {
    switch (currentPage) {
      case Page.Home: return <Home onNavigate={setCurrentPage} />;
      case Page.About: return <About />;
      case Page.Ministries: return <Ministries />;
      case Page.Community: return <Community />;
      case Page.Support: return <Support />;
      case Page.Admin: return <Admin />;
      default: return <Home onNavigate={setCurrentPage} />;
    }
  };

  return (
    <div className="flex flex-col min-h-screen selection:bg-orange-100">
      <Navbar currentPage={currentPage} onNavigate={setCurrentPage} />
      <main className="flex-grow pt-16">
        {renderPage()}
      </main>
      <Footer onNavigate={setCurrentPage} />
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Page } from '../types';
import { Menu, X, Heart } from 'lucide-react';

interface NavbarProps {
  currentPage: Page;
  onNavigate: (page: Page) => void;
}

const Navbar: React.FC<NavbarProps> = ({ currentPage, onNavigate }) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const navItems = [
    { label: '홈', value: Page.Home },
    { label: '선교회 소개', value: Page.About },
    { label: '사역 안내', value: Page.Ministries },
    { label: '나눔 광장', value: Page.Community },
    { label: '후원 안내', value: Page.Support },
  ];

  return (
    <nav className="fixed top-0 left-0 right-0 z-50 bg-white/80 backdrop-blur-md border-b border-orange-100 shadow-sm">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">
          {/* Logo */}
          <div 
            className="flex items-center gap-2 cursor-pointer group"
            onClick={() => onNavigate(Page.Home)}
          >
            <div className="w-10 h-10 bg-orange-100 rounded-full flex items-center justify-center group-hover:bg-orange-200 transition-colors">
              <Heart className="text-orange-600 w-6 h-6" />
            </div>
            <span className="text-xl font-bold text-gray-800 tracking-tight">헵시바 선교회</span>
          </div>

          {/* Desktop Menu */}
          <div className="hidden md:flex items-center space-x-8">
            {navItems.map((item) => (
              <button
                key={item.value}
                onClick={() => onNavigate(item.value)}
                className={`text-sm font-medium transition-colors ${
                  currentPage === item.value 
                    ? 'text-orange-600' 
                    : 'text-gray-600 hover:text-orange-500'
                }`}
              >
                {item.label}
              </button>
            ))}
            <button
              onClick={() => onNavigate(Page.Support)}
              className="px-4 py-2 bg-orange-500 text-white rounded-full text-sm font-medium hover:bg-orange-600 transition-shadow shadow-md hover:shadow-lg"
            >
              후원하기
            </button>
          </div>

          {/* Mobile Toggle */}
          <div className="md:hidden flex items-center">
            <button
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              className="text-gray-600 p-2"
            >
              {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isMobileMenuOpen && (
        <div className="md:hidden bg-white border-t border-orange-50 px-4 py-4 space-y-2 animate-in slide-in-from-top duration-300">
          {navItems.map((item) => (
            <button
              key={item.value}
              onClick={() => {
                onNavigate(item.value);
                setIsMobileMenuOpen(false);
              }}
              className={`block w-full text-left px-4 py-3 rounded-lg text-base font-medium ${
                currentPage === item.value 
                  ? 'bg-orange-50 text-orange-600' 
                  : 'text-gray-600 hover:bg-gray-50'
              }`}
            >
              {item.label}
            </button>
          ))}
          <button
            onClick={() => {
              onNavigate(Page.Support);
              setIsMobileMenuOpen(false);
            }}
            className="block w-full text-center px-4 py-3 bg-orange-500 text-white rounded-lg font-medium shadow-sm"
          >
            후원하기
          </button>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React, { useState, useEffect } from 'react';
import { Testimony, GuestbookEntry, Inquiry } from '../types';
import { MessageSquare, PenTool, Send, Heart } from 'lucide-react';

const Community: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'guestbook' | 'testimony' | 'inquiry'>('testimony');

  // States to manage local data (simulated backend)
  const [testimonies, setTestimonies] = useState<Testimony[]>([]);
  const [guestbook, setGuestbook] = useState<GuestbookEntry[]>([]);

  // Form states
  const [guestbookName, setGuestbookName] = useState('');
  const [guestbookMsg, setGuestbookMsg] = useState('');
  const [inquiryData, setInquiryData] = useState({ name: '', email: '', subject: '', message: '' });

  useEffect(() => {
    // Initial data load
    const savedTestimonies = localStorage.getItem('testimonies');
    const savedGuestbook = localStorage.getItem('guestbook');

    if (savedTestimonies) setTestimonies(JSON.parse(savedTestimonies));
    else {
      const initial: Testimony[] = [
        { id: '1', author: '김은혜', title: '금요집회에서 만난 주님', content: '오랫동안 마음의 병으로 힘들었는데 지난 금요치유집회에서 뜨거운 성령의 임재를 체험하며 모든 불안함이 사라졌습니다.', date: '2024-05-10' },
        { id: '2', author: '이충성', title: '사역을 통한 감사', content: '밥퍼 사역에 자원봉사자로 참여하며 오히려 제가 더 큰 위로를 받았습니다. 작은 나눔이 얼마나 소중한지 깨달았습니다.', date: '2024-05-12' }
      ];
      setTestimonies(initial);
      localStorage.setItem('testimonies', JSON.stringify(initial));
    }

    if (savedGuestbook) setGuestbook(JSON.parse(savedGuestbook));
    else {
      const initial: GuestbookEntry[] = [
        { id: '1', author: '박서준', message: '선교회 홈페이지가 너무 따뜻하고 예쁘네요! 자주 들르겠습니다.', date: '2024-05-14' }
      ];
      setGuestbook(initial);
      localStorage.setItem('guestbook', JSON.stringify(initial));
    }
  }, []);

  const handleGuestbookSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!guestbookName || !guestbookMsg) return;
    const newEntry: GuestbookEntry = {
      id: Date.now().toString(),
      author: guestbookName,
      message: guestbookMsg,
      date: new Date().toISOString().split('T')[0]
    };
    const updated = [newEntry, ...guestbook];
    setGuestbook(updated);
    localStorage.setItem('guestbook', JSON.stringify(updated));
    setGuestbookName('');
    setGuestbookMsg('');
    alert('방명록이 등록되었습니다.');
  };

  const handleInquirySubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newInquiry: Inquiry = {
      id: Date.now().toString(),
      ...inquiryData,
      status: 'pending',
      date: new Date().toISOString().split('T')[0]
    };
    const savedInquiries = JSON.parse(localStorage.getItem('inquiries') || '[]');
    localStorage.setItem('inquiries', JSON.stringify([newInquiry, ...savedInquiries]));
    setInquiryData({ name: '', email: '', subject: '', message: '' });
    alert('문의가 제출되었습니다. 확인 후 연락드리겠습니다.');
  };

  return (
    <div className="py-24 bg-[#FCFBF7]">
      <div className="max-w-4xl mx-auto px-4">
        <header className="text-center mb-16">
          <h1 className="text-4xl font-bold text-gray-900 serif mb-4">나눔 광장</h1>
          <p className="text-gray-500">은혜로운 간증과 따뜻한 인사를 나누는 공간입니다.</p>
        </header>

        {/* Tabs */}
        <div className="flex justify-center mb-12 bg-white p-2 rounded-2xl shadow-sm border border-orange-50">
          <button 
            onClick={() => setActiveTab('testimony')}
            className={`px-6 py-3 rounded-xl font-bold transition-all ${activeTab === 'testimony' ? 'bg-orange-500 text-white' : 'text-gray-500 hover:bg-gray-50'}`}
          >
            은혜의 간증
          </button>
          <button 
            onClick={() => setActiveTab('guestbook')}
            className={`px-6 py-3 rounded-xl font-bold transition-all ${activeTab === 'guestbook' ? 'bg-orange-500 text-white' : 'text-gray-500 hover:bg-gray-50'}`}
          >
            방명록
          </button>
          <button 
            onClick={() => setActiveTab('inquiry')}
            className={`px-6 py-3 rounded-xl font-bold transition-all ${activeTab === 'inquiry' ? 'bg-orange-500 text-white' : 'text-gray-500 hover:bg-gray-50'}`}
          >
            문의하기
          </button>
        </div>

        {/* Content Rendering */}
        <div className="space-y-8 animate-in fade-in duration-500">
          {activeTab === 'testimony' && (
            <div className="space-y-6">
              <div className="flex justify-end">
                <button className="flex items-center gap-2 bg-orange-100 text-orange-600 px-6 py-3 rounded-xl font-bold hover:bg-orange-200 transition-colors">
                  <PenTool size={18} />
                  간증 작성하기
                </button>
              </div>
              {testimonies.map(t => (
                <article key={t.id} className="bg-white p-8 rounded-[2rem] shadow-sm border border-orange-50 space-y-4 hover:shadow-md transition-shadow">
                  <div className="flex justify-between items-start">
                    <h3 className="text-xl font-bold text-gray-800 serif">{t.title}</h3>
                    <span className="text-sm text-gray-400">{t.date}</span>
                  </div>
                  <p className="text-gray-600 leading-relaxed whitespace-pre-wrap">{t.content}</p>
                  <div className="flex items-center gap-2 text-sm text-gray-500 pt-4 border-t border-gray-50">
                    <Heart size={14} className="text-orange-400" />
                    <span>글쓴이: {t.author}</span>
                  </div>
                </article>
              ))}
            </div>
          )}

          {activeTab === 'guestbook' && (
            <div className="space-y-12">
              <form onSubmit={handleGuestbookSubmit} className="bg-white p-8 rounded-[2.5rem] shadow-md border border-orange-100 space-y-4">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <input 
                    type="text" 
                    placeholder="작성자 성함" 
                    value={guestbookName}
                    onChange={(e) => setGuestbookName(e.target.value)}
                    className="w-full px-5 py-3 rounded-xl border border-gray-100 focus:outline-none focus:ring-2 focus:ring-orange-200 transition-all bg-gray-50"
                  />
                </div>
                <textarea 
                  placeholder="따뜻한 인사를 남겨주세요." 
                  rows={3}
                  value={guestbookMsg}
                  onChange={(e) => setGuestbookMsg(e.target.value)}
                  className="w-full px-5 py-3 rounded-xl border border-gray-100 focus:outline-none focus:ring-2 focus:ring-orange-200 transition-all bg-gray-50 resize-none"
                ></textarea>
                <div className="flex justify-end">
                  <button type="submit" className="flex items-center gap-2 bg-orange-500 text-white px-8 py-3 rounded-xl font-bold hover:bg-orange-600 transition-colors">
                    <Send size={18} />
                    등록하기
                  </button>
                </div>
              </form>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {guestbook.map(g => (
                  <div key={g.id} className="bg-white/70 p-6 rounded-3xl border border-white shadow-sm hover:shadow-md transition-shadow">
                    <div className="flex justify-between items-center mb-3">
                      <span className="font-bold text-gray-800">{g.author}</span>
                      <span className="text-xs text-gray-400">{g.date}</span>
                    </div>
                    <p className="text-gray-600 text-sm leading-relaxed">{g.message}</p>
                  </div>
                ))}
              </div>
            </div>
          )}

          {activeTab === 'inquiry' && (
            <div className="bg-white p-10 md:p-16 rounded-[3rem] shadow-xl border border-orange-50 space-y-10">
              <div className="text-center">
                <MessageSquare className="w-12 h-12 text-orange-400 mx-auto mb-4" />
                <h2 className="text-2xl font-bold text-gray-800 serif">무엇을 도와드릴까요?</h2>
                <p className="text-gray-500 mt-2">기도 제목이나 선교회 관련 궁금하신 사항을 남겨주세요.</p>
              </div>
              <form onSubmit={handleInquirySubmit} className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-sm font-bold text-gray-600 ml-1">이름</label>
                    <input 
                      required
                      type="text" 
                      value={inquiryData.name}
                      onChange={(e) => setInquiryData({...inquiryData, name: e.target.value})}
                      className="w-full px-6 py-4 rounded-2xl border border-gray-200 focus:outline-none focus:ring-2 focus:ring-orange-200 transition-all bg-gray-50"
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-sm font-bold text-gray-600 ml-1">이메일</label>
                    <input 
                      required
                      type="email" 
                      value={inquiryData.email}
                      onChange={(e) => setInquiryData({...inquiryData, email: e.target.value})}
                      className="w-full px-6 py-4 rounded-2xl border border-gray-200 focus:outline-none focus:ring-2 focus:ring-orange-200 transition-all bg-gray-50"
                    />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-gray-600 ml-1">제목</label>
                  <input 
                    required
                    type="text" 
                    value={inquiryData.subject}
                    onChange={(e) => setInquiryData({...inquiryData, subject: e.target.value})}
                    className="w-full px-6 py-4 rounded-2xl border border-gray-200 focus:outline-none focus:ring-2 focus:ring-orange-200 transition-all bg-gray-50"
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-gray-600 ml-1">상세 내용</label>
                  <textarea 
                    required
                    rows={5}
                    value={inquiryData.message}
                    onChange={(e) => setInquiryData({...inquiryData, message: e.target.value})}
                    className="w-full px-6 py-4 rounded-2xl border border-gray-200 focus:outline-none focus:ring-2 focus:ring-orange-200 transition-all bg-gray-50 resize-none"
                  ></textarea>
                </div>
                <button 
                  type="submit" 
                  className="w-full py-5 bg-orange-500 text-white rounded-2xl font-bold text-lg shadow-lg hover:bg-orange-600 transition-all"
                >
                  보내기
                </button>
              </form>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Community;

import React, { useState, useEffect } from 'react';
import { Inquiry, Sponsorship, GuestbookEntry } from '../types';
import { LayoutDashboard, MessageSquare, Heart, BookOpen, Trash2, CheckCircle } from 'lucide-react';

const Admin: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const [view, setView] = useState<'inquiries' | 'sponsorships' | 'guestbook'>('inquiries');

  const [inquiries, setInquiries] = useState<Inquiry[]>([]);
  const [sponsorships, setSponsorships] = useState<Sponsorship[]>([]);
  const [guestbook, setGuestbook] = useState<GuestbookEntry[]>([]);

  useEffect(() => {
    if (isLoggedIn) {
      setInquiries(JSON.parse(localStorage.getItem('inquiries') || '[]'));
      setSponsorships(JSON.parse(localStorage.getItem('sponsorships') || '[]'));
      setGuestbook(JSON.parse(localStorage.getItem('guestbook') || '[]'));
    }
  }, [isLoggedIn]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'hephzibah777') { // Mock admin password
      setIsLoggedIn(true);
    } else {
      alert('비밀번호가 틀렸습니다.');
    }
  };

  const deleteItem = (id: string, type: string) => {
    if (!confirm('정말 삭제하시겠습니까?')) return;

    let key = '';
    let setter: any;
    let current: any[];

    if (type === 'inquiry') { key = 'inquiries'; setter = setInquiries; current = inquiries; }
    else if (type === 'sponsorship') { key = 'sponsorships'; setter = setSponsorships; current = sponsorships; }
    else if (type === 'guestbook') { key = 'guestbook'; setter = setGuestbook; current = guestbook; }

    const updated = current.filter(item => item.id !== id);
    setter(updated);
    localStorage.setItem(key, JSON.stringify(updated));
  };

  if (!isLoggedIn) {
    return (
      <div className="min-h-[70vh] flex items-center justify-center p-4">
        <form onSubmit={handleLogin} className="bg-white p-8 rounded-3xl shadow-xl border border-gray-100 w-full max-w-md space-y-6">
          <div className="text-center">
            <LayoutDashboard className="w-12 h-12 text-orange-500 mx-auto mb-4" />
            <h1 className="text-2xl font-bold text-gray-800">관리자 로그인</h1>
            <p className="text-sm text-gray-500 mt-2">인증 후 관리 대시보드에 접근할 수 있습니다.</p>
          </div>
          <input 
            type="password" 
            placeholder="비밀번호" 
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="w-full px-5 py-3 rounded-xl border border-gray-200 focus:outline-none focus:ring-2 focus:ring-orange-200"
          />
          <button type="submit" className="w-full py-3 bg-gray-800 text-white rounded-xl font-bold hover:bg-gray-900 transition-colors">
            로그인
          </button>
        </form>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 py-12">
      <header className="flex flex-col md:flex-row justify-between items-center gap-6 mb-12">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 serif">관리자 대시보드</h1>
          <p className="text-gray-500">홈페이지의 모든 제출 사항을 관리합니다.</p>
        </div>
        <div className="flex bg-gray-100 p-1 rounded-2xl">
          <button 
            onClick={() => setView('inquiries')}
            className={`flex items-center gap-2 px-5 py-2 rounded-xl text-sm font-bold transition-all ${view === 'inquiries' ? 'bg-white shadow text-gray-800' : 'text-gray-500'}`}
          >
            <MessageSquare size={16} /> 문의 ({inquiries.length})
          </button>
          <button 
            onClick={() => setView('sponsorships')}
            className={`flex items-center gap-2 px-5 py-2 rounded-xl text-sm font-bold transition-all ${view === 'sponsorships' ? 'bg-white shadow text-gray-800' : 'text-gray-500'}`}
          >
            <Heart size={16} /> 후원 ({sponsorships.length})
          </button>
          <button 
            onClick={() => setView('guestbook')}
            className={`flex items-center gap-2 px-5 py-2 rounded-xl text-sm font-bold transition-all ${view === 'guestbook' ? 'bg-white shadow text-gray-800' : 'text-gray-500'}`}
          >
            <BookOpen size={16} /> 방명록 ({guestbook.length})
          </button>
        </div>
      </header>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 overflow-hidden">
        {view === 'inquiries' && (
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead className="bg-gray-50 border-b border-gray-100">
                <tr>
                  <th className="px-8 py-5 text-xs font-bold text-gray-400 uppercase">날짜</th>
                  <th className="px-8 py-5 text-xs font-bold text-gray-400 uppercase">이름 / 이메일</th>
                  <th className="px-8 py-5 text-xs font-bold text-gray-400 uppercase">내용</th>
                  <th className="px-8 py-5 text-xs font-bold text-gray-400 uppercase text-right">관리</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {inquiries.map(item => (
                  <tr key={item.id} className="hover:bg-gray-50/50 transition-colors">
                    <td className="px-8 py-6 text-sm text-gray-500">{item.date}</td>
                    <td className="px-8 py-6">
                      <p className="font-bold text-gray-800">{item.name}</p>
                      <p className="text-xs text-gray-400">{item.email}</p>
                    </td>
                    <td className="px-8 py-6">
                      <p className="font-medium text-gray-700">{item.subject}</p>
                      <p className="text-sm text-gray-500 line-clamp-1">{item.message}</p>
                    </td>
