        )}

        {((view === 'inquiries' && inquiries.length === 0) || 
          (view === 'sponsorships' && sponsorships.length === 0) || 
          (view === 'guestbook' && guestbook.length === 0)) && (
          <div className="py-20 text-center text-gray-400">
            데이터가 없습니다.
          </div>
        )}
