import React, { useState, useEffect } from 'react';
import { Inquiry, Sponsorship, GuestbookEntry, Testimony } from '../types';
import { LayoutDashboard, MessageSquare, Heart, BookOpen, Trash2, Quote } from 'lucide-react';

const Admin: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const [view, setView] = useState<'inquiries' | 'sponsorships' | 'guestbook' | 'testimonies'>('inquiries');

  const [inquiries, setInquiries] = useState<Inquiry[]>([]);
  const [sponsorships, setSponsorships] = useState<Sponsorship[]>([]);
  const [guestbook, setGuestbook] = useState<GuestbookEntry[]>([]);
  const [testimonies, setTestimonies] = useState<Testimony[]>([]);

  useEffect(() => {
    if (isLoggedIn) {
      setInquiries(JSON.parse(localStorage.getItem('inquiries') || '[]'));
      setSponsorships(JSON.parse(localStorage.getItem('sponsorships') || '[]'));
      setGuestbook(JSON.parse(localStorage.getItem('guestbook') || '[]'));
      setTestimonies(JSON.parse(localStorage.getItem('testimonies') || '[]'));
    }
  }, [isLoggedIn]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (password === 'hephzibah777') { // Mock admin password
      setIsLoggedIn(true);
    } else {
      alert('비밀번호가 틀렸습니다.');
    }
  };

  const deleteItem = (id: string, type: string) => {
    if (!confirm('정말 삭제하시겠습니까?')) return;

    let key = '';
    let setter: any;
    let current: any[];

    if (type === 'inquiry') { key = 'inquiries'; setter = setInquiries; current = inquiries; }
    else if (type === 'sponsorship') { key = 'sponsorships'; setter = setSponsorships; current = sponsorships; }
    else if (type === 'guestbook') { key = 'guestbook'; setter = setGuestbook; current = guestbook; }
    else if (type === 'testimony') { key = 'testimonies'; setter = setTestimonies; current = testimonies; }

    const updated = current.filter(item => item.id !== id);
    setter(updated);
    localStorage.setItem(key, JSON.stringify(updated));
  };

  if (!isLoggedIn) {
    return (
      <div className="min-h-[70vh] flex items-center justify-center p-4">
        <form onSubmit={handleLogin} className="bg-white p-8 rounded-3xl shadow-xl border border-gray-100 w-full max-w-md space-y-6">
          <div className="text-center">
            <LayoutDashboard className="w-12 h-12 text-orange-500 mx-auto mb-4" />
            <h1 className="text-2xl font-bold text-gray-800">관리자 로그인</h1>
            <p className="text-sm text-gray-500 mt-2">인증 후 관리 대시보드에 접근할 수 있습니다.</p>
          </div>
          <input 
            type="password" 
            placeholder="비밀번호" 
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="w-full px-5 py-3 rounded-xl border border-gray-200 focus:outline-none focus:ring-2 focus:ring-orange-200 transition-all"
          />
          <button type="submit" className="w-full py-3 bg-gray-800 text-white rounded-xl font-bold hover:bg-gray-900 transition-colors">
            로그인
          </button>
        </form>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 py-12">
      <header className="flex flex-col lg:flex-row justify-between items-center gap-6 mb-12">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 serif">관리자 대시보드</h1>
          <p className="text-gray-500">홈페이지의 모든 제출 사항을 관리합니다.</p>
        </div>
        <div className="flex flex-wrap justify-center bg-gray-100 p-1 rounded-2xl gap-1">
          <button 
            onClick={() => setView('inquiries')}
            className={`flex items-center gap-2 px-5 py-2 rounded-xl text-sm font-bold transition-all ${view === 'inquiries' ? 'bg-white shadow text-gray-800' : 'text-gray-500 hover:bg-gray-200'}`}
          >
            <MessageSquare size={16} /> 문의 ({inquiries.length})
          </button>
          <button 
            onClick={() => setView('sponsorships')}
            className={`flex items-center gap-2 px-5 py-2 rounded-xl text-sm font-bold transition-all ${view === 'sponsorships' ? 'bg-white shadow text-gray-800' : 'text-gray-500 hover:bg-gray-200'}`}
          >
            <Heart size={16} /> 후원 ({sponsorships.length})
          </button>
          <button 
            onClick={() => setView('guestbook')}
            className={`flex items-center gap-2 px-5 py-2 rounded-xl text-sm font-bold transition-all ${view === 'guestbook' ? 'bg-white shadow text-gray-800' : 'text-gray-500 hover:bg-gray-200'}`}
          >
            <BookOpen size={16} /> 방명록 ({guestbook.length})
          </button>
          <button 
            onClick={() => setView('testimonies')}
            className={`flex items-center gap-2 px-5 py-2 rounded-xl text-sm font-bold transition-all ${view === 'testimonies' ? 'bg-white shadow text-gray-800' : 'text-gray-500 hover:bg-gray-200'}`}
          >
            <Quote size={16} /> 간증 ({testimonies.length})
          </button>
        </div>
      </header>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-100 overflow-hidden">
        {view === 'inquiries' && (
