 * }
 */

import { Inquiry, Sponsorship, GuestbookEntry, Testimony } from './types';

// 실제 사용 시 배포된 구글 앱스 스크립트 URL로 변경하세요.
// 현재는 데모를 위해 localStorage를 Mock DB로 사용하되, 구조는 API 통신과 동일하게 비동기로 설계합니다.
const API_URL = ''; 

export const db = {
  async save(type: 'inquiry' | 'sponsorship' | 'guestbook' | 'testimony', payload: any): Promise<boolean> {
    console.log(`Saving ${type} to Spreadsheet...`, payload);

    // 실제 API 연동 로직
    if (API_URL) {
      try {
        const response = await fetch(API_URL, {
          method: 'POST',
          body: JSON.stringify({ type, ...payload })
        });
        return response.ok;
      } catch (e) {
        console.error(e);
        return false;
      }
    }

    // Fallback: API URL이 없을 경우 localStorage 사용 (개발용)
    await new Promise(resolve => setTimeout(resolve, 800)); // 통신 지연 시뮬레이션
    const storageKey = type === 'testimony' ? 'testimonies' : 
                      type === 'guestbook' ? 'guestbook' : 
                      type === 'inquiry' ? 'inquiries' : 'sponsorships';

    const existing = JSON.parse(localStorage.getItem(storageKey) || '[]');
    localStorage.setItem(storageKey, JSON.stringify([{ id: Date.now().toString(), date: new Date().toISOString().split('T')[0], ...payload }, ...existing]));
    return true;
  },

  async getAll(): Promise<{
    inquiries: Inquiry[],
    sponsorships: Sponsorship[],
    guestbook: GuestbookEntry[],
    testimonies: Testimony[]
  }> {
    // 실제 API 연동 로직
    if (API_URL) {
      try {
        const response = await fetch(API_URL);
        const rawData = await response.json();
        // 여기서 구글 시트 데이터를 파싱하여 리턴하는 로직 필요
        console.log('Fetched from Sheet:', rawData);
      } catch (e) {
        console.error(e);
      }
    }

    // Fallback 로직
    await new Promise(resolve => setTimeout(resolve, 1000));
    return {
      inquiries: JSON.parse(localStorage.getItem('inquiries') || '[]'),
      sponsorships: JSON.parse(localStorage.getItem('sponsorships') || '[]'),
      guestbook: JSON.parse(localStorage.getItem('guestbook') || '[]'),
      testimonies: JSON.parse(localStorage.getItem('testimonies') || '[]')
    };
  },

  async delete(type: string, id: string): Promise<boolean> {
    const storageKey = type === 'testimony' ? 'testimonies' : 
                      type === 'guestbook' ? 'guestbook' : 
                      type === 'inquiry' ? 'inquiries' : 'sponsorships';

    const existing = JSON.parse(localStorage.getItem(storageKey) || '[]');
    const filtered = existing.filter((item: any) => item.id !== id);
    localStorage.setItem(storageKey, JSON.stringify(filtered));
    return true;
  }
};

