 *   var id = Utilities.getUuid();
 *   var date = new Date().toISOString().split('T')[0];
 *   var payload = { ...data, id: id, date: date };
 *   sheet.appendRow([new Date(), data.type, JSON.stringify(payload)]);
 *   return ContentService.createTextOutput(JSON.stringify({result: 'success', data: payload})).setMimeType(ContentService.MimeType.JSON);
