/**
 * [헵시바 선교회 구글 스프레드시트 DB 설정 가이드]
 * 1. 구글 스프레드시트 생성
 * 2. '확장 프로그램' > 'Apps Script' 클릭
 * 3. 아래 코드를 복사해서 붙여넣고 '배포' > '새 배포' > '웹 앱' 설정
 *    - 설명: Hephzibah DB API v2
 *    - 다음 사용자 권한으로 실행: 나(본인 계정)
 *    - 액세스 권한이 있는 사용자: 모든 사용자(Anyone)
 * 4. 생성된 웹 앱 URL을 아래 API_URL 상수에 붙여넣으세요.
 * 
 * [최신 Google Apps Script 소스코드]
 * function doPost(e) {
 *   var sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
 *   var content = e.postData.contents;
 *   var data = JSON.parse(content);
 *   
 *   if (data.action === 'delete') {
 *     var rows = sheet.getDataRange().getValues();
 *     var deleted = false;
 *     for (var i = rows.length - 1; i >= 0; i--) {
 *       try {
 *         var rowData = JSON.parse(rows[i][2]);
 *         if (rowData.id === data.id) {
 *           sheet.deleteRow(i + 1);
 *           deleted = true;
 *         }
 *       } catch(err) {}
 *     }
 *     return ContentService.createTextOutput(JSON.stringify({result: deleted ? 'deleted' : 'not_found'})).setMimeType(ContentService.MimeType.JSON);
 *   }
 *   
 *   var id = Utilities.getUuid();
 *   var date = new Date().toISOString().split('T')[0];
 *   var payload = { ...data, id: id, date: date };
 *   // data.dbCategory를 2번째 열에 저장하여 sponsorship type과 혼동되지 않게 함
 *   sheet.appendRow([new Date(), data.dbCategory, JSON.stringify(payload)]);
 *   return ContentService.createTextOutput(JSON.stringify({result: 'success', data: payload})).setMimeType(ContentService.MimeType.JSON);
 * }
 * 
 * function doGet() {
 *   var sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
